function buildSentencePattern(term) {
  const escaped = term.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  const boundary = /^\[/.test(term) ? '' : '\\b';
  return new RegExp(`[^.!?]*${boundary}${escaped}${boundary}[^.!?]*[.!?]`, 'gi');
}

